-- ============================================================
-- SCJC NDT 无损检测管理系统 - 初始化数据库脚本
-- 数据库: scjc_ndt (utf8mb4)
-- ============================================================

CREATE DATABASE IF NOT EXISTS `scjc_ndt`
  DEFAULT CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;

USE `scjc_ndt`;

-- ============================================================
-- 一、部门/组织表
-- ============================================================
DROP TABLE IF EXISTS `user_project_rel`;
DROP TABLE IF EXISTS `user_role_rel`;
DROP TABLE IF EXISTS `signature_record`;
DROP TABLE IF EXISTS `process_card`;
DROP TABLE IF EXISTS `report_record`;
DROP TABLE IF EXISTS `report_template`;
DROP TABLE IF EXISTS `system_image`;
DROP TABLE IF EXISTS `inspection_record`;
DROP TABLE IF EXISTS `sys_project`;
DROP TABLE IF EXISTS `sys_user`;
DROP TABLE IF EXISTS `sys_role`;
DROP TABLE IF EXISTS `sys_dept`;

CREATE TABLE `sys_dept` (
    `id` BIGINT NOT NULL AUTO_INCREMENT,
    `parent_id` BIGINT DEFAULT NULL COMMENT '父节点ID',
    `dept_name` VARCHAR(100) NOT NULL COMMENT '部门名称',
    `dept_type` VARCHAR(20) NOT NULL COMMENT 'COMPANY/BU/PROJECT',
    `bu_name` VARCHAR(50) DEFAULT NULL COMMENT '所属事业部(成都/重庆/新疆/长庆)',
    `sort` INT DEFAULT 0,
    `status` TINYINT DEFAULT 1 COMMENT '1启用 0禁用',
    `create_time` DATETIME DEFAULT CURRENT_TIMESTAMP,
    `update_time` DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    `deleted` TINYINT DEFAULT 0 COMMENT '逻辑删除',
    PRIMARY KEY (`id`),
    INDEX `idx_parent_id` (`parent_id`),
    INDEX `idx_dept_type` (`dept_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='部门/组织表';

