             {"label": "Ⅲ级", "bind": "level_iii", "width": "80px"},
             {"label": "Ⅳ级", "bind": "level_iv", "width": "80px"}
           ],
           "data_source": "inspection_record",
           "data_filter": "current"
         },
         {
           "type": "signature",
           "label": "签字区",
           "signatories": [
             {"order": 0, "label": "检测人员", "role": null, "manual": true},
             {"order": 1, "label": "技术负责人", "role": "TECHNICAL_LEADER", "manual": false},
             {"order": 2, "label": "项目经理", "role": "PROJECT_MANAGER", "manual": false}
           ]
         }
       ]
     },
     {
       "name": "附页",
       "paper": "A4",
       "orientation": "portrait",
       "sections": [
         {
           "type": "header",
           "label": "射线检测报告附页",
           "style": {"fontSize": "16px", "fontWeight": "bold", "textAlign": "center"}
