             ]
           ]
         },
         {
           "type": "table",
           "label": "缺陷详细记录(续)",
           "columns": [
             {"label": "位置", "bind": "defect_positions[].pos", "width": "60px"},
             {"label": "其他缺陷", "bind": "defect_positions[].defect", "width": "150px"},
             {"label": "其他缺陷及长度", "bind": "defect_positions[].length", "width": "120px"},
             {"label": "级别", "bind": "defect_positions[].level", "width": "60px"}
           ],
           "data_source": "defect_positions",
           "data_filter": "all",
           "max_rows": 15
         },
         {
           "type": "text",
           "label": "备注区",
           "content": "备注: {remark}"
         }
       ]
     }
   ],
   "image_areas": [
     {
       "area_id": "film_layout",
       "page": "首页",
       "label": "底片布置图",
       "position": {"x": "5%", "y": "45%", "width": "90%", "height": "30%"},
       "description": "拖入或选择透照方式示意图/底片图片"
