   ],
   "signature_flow": [
     {"order": 1, "role": "TECHNICAL_LEADER", "label": "技术负责人", "required": true},
     {"order": 2, "role": "PROJECT_MANAGER", "label": "项目经理", "required": true}
   ]
 }',
